    vi.doMock('../../src/heartbeat/config.js', () => ({
      configPath: () => '/nonexistent/config.toml',
      loadConfig: () => ({
        heartbeat_interval: '5m',
        auto_push: true,
        projects: [],
        watch_dirs: [],
        log_level: 'info',
      }),
      intervalToSeconds: (s: string) => {
        const match = s.match(/^(\d+)(s|m|h)$/)
